import { IMessageComposer } from '@nitrots/nitro-renderer';

export class HighLowStartComposer implements IMessageComposer<Array<number>> {
    private _data: Array<number>;

    /**
     * @param bet The amount of credits the user wants to wager (int).
     */
    constructor(bet: number) {
        // guard a bit so we never send NaN/undefined
        const safeBet = Math.max(0, Number.isFinite(bet) ? Math.floor(bet) : 0);
        this._data = [safeBet];
    }

    public getMessageArray(): Array<number> {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
